import vex
import ag2

# Install: pip install ag2 vex-sdk

@vex.hook()
def legal_compliance_check(message: ag2.Message) -> ag2.Message:
    # Redact PII and privileged content
    cleaned = vex.redact_pii(message.content, categories=['names', 'ssn', 'client_info'])
    if vex.detect_privilege(cleaned):
        vex.alert('Potential privilege breach detected')
        return ag2.Message(content='[REDACTED - PRIVILEGE PROTECTED]')
    # Validate legal citations
    if vex.validate_citations(cleaned, db='caselaw'):
        return ag2.Message(content=cleaned)
    else:
        return ag2.Message(content='[CITATION INVALID - REQUIRES ATTORNEY REVIEW]')

# Register with AG2 group chat
config = ag2.GroupChatConfig(message_hooks=[legal_compliance_check])

import vex
import ag2

@vex.hook(require_human_review=True)
def attorney_review_required(message: ag2.Message) -> ag2.Message:
    if 'legal advice' in message.content.lower() or 'filing' in message.content.lower():
        ticket = vex.create_review_ticket(
            content=message.content,
            category='legal_output',
            requires_approval='licensed_attorney'
        )
        return ag2.Message(content=f'PENDING ATTORNEY REVIEW: {ticket.id}')
    return message

# AG2 integration
chat = ag2.GroupChat(
    agents=[researcher, drafter],
    message_hooks=[attorney_review_required]
)

import vex
import ag2

@vex.hook()
def legal_conversation_guard(message: ag2.Message, context: ag2.GroupChatContext) -> ag2.Message:
    # Check for off-topic drift
    topic_drift = vex.semantic_drift(context.messages, target_topic='contract dispute analysis')
    if topic_drift > 0.7:
        return ag2.Message(content='[CONVERSATION DRIFT DETECTED] Refocus: contract dispute analysis')

    # Validate group consensus
    if len(context.messages) > 5:
        consensus = vex.group_consensus(context.messages[-5:])
        if not vex.fact_check(consensus, domain='legal', sources=['uscourts.gov']):
            vex.flag('Group consensus contains unverified legal claims')
    return message

# Apply to AG2 group chat
group_chat = ag2.GroupChat(message_hooks=[legal_conversation_guard])
